#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int maxManhattanDistance(int** points, int N, int L, int R) {
    int maxDistance = 0;
    for (int i = L; i <= R; i++) {
        for (int j = i + 1; j <= R; j++) {
            int distance = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1]);
            if (distance > maxDistance) {
                maxDistance = distance;
            }
        }
    }
    return maxDistance;
}

int main() {
    int N;
    scanf("%d", &N);
    int** points = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        points[i] = (int*)malloc(2 * sizeof(int));
        scanf("%d %d", &points[i][0], &points[i][1]);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        char query;
        scanf(" %c", &query);
        if (query == 'U') {
            int index, x, y;
            scanf("%d %d %d", &index, &x, &y);
            points[index][0] = x;
            points[index][1] = y;
        } else if (query == 'Q') {
            int L, R;
            scanf("%d %d", &L, &R);
            printf("%d\n", maxManhattanDistance(points, N, L, R));
        }
    }
    return 0;
}

